const express = require('express'); // Importing Express framework 
const app = express();               // Initializing an instance of the application using 'app' as a reference to it  
var bodyParser=require("body-parser");//Import for parsing incoming requests with JSON payloads. This is used here in order not only parse but also typecasting and validating data 
const mongoose = require('mongoose'); // Import MongoDB driver/ORM package from NodeJS to interact directly into the database (Mongodb)  
var cors=require("cors");             //Import for enabling CORS on your server. This is used here in order not only handle requests but also allow cross-origin resource sharing 
app.use(bodyParser.json());          // Middleware to parse JSON bodies and make them available through req.body  
var jwt = require('express-jwt');     // Import for handling JWT authentication (to protect routes)   
const config  =require("./config/keys");  //Importing the configuration file which contains database URLs, secret keys etc... This is used here to connect with MongoDB  
app.use(cors());                      // Enable CORS on all our server's endpoints (this will allow us not only handle requests but also share resources)   
mongoose.connect(config.mongodbURI);  // Connecting the application using 'Mongooes'. This is used to interact with MongoDB  
app.use(jwt({ secret: config.secret, algorithms: ['HS256'] }));// Middleware for handling JWT authentication (to protect routes)   
const PORT = process.env.PORT || 3091; // Set the port to either Heroku's assigned or defaulted value of 3091  
app.listen(PORT, () => { console.log('Server is running on Port: ' + PORT); });// Listening for requests at this specific address and logging a message when it starts up